import{_ as a,c as i,o as t,aN as e}from"./chunks/framework.CqA5BTDU.js";const r=JSON.parse('{"title":"SSH 客户端与密钥","description":"","frontmatter":{},"headers":[],"relativePath":"03.远程运维/01-SSH客户端与密钥.md","filePath":"03.远程运维/01-SSH客户端与密钥.md","lastUpdated":null}'),n={name:"03.远程运维/01-SSH客户端与密钥.md"};function p(h,s,d,l,o,k){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="ssh-客户端与密钥" tabindex="-1">SSH 客户端与密钥 <a class="header-anchor" href="#ssh-客户端与密钥" aria-label="Permalink to &quot;SSH 客户端与密钥&quot;">​</a></h1><p>运维的大部分操作发生在远端服务器上——不是坐在机房里敲键盘，而是通过网络连过去。网络不可靠、服务器身份要验证、登录凭据要管理、多台机器要区分——SSH 是处理这些问题的基础工具。</p><p>这篇文章梳理客户端侧的连接方式、密钥管理、跳板访问和端口转发，以及连接问题排查。</p><h2 id="一、一份-ssh-连接里有两层验证" tabindex="-1">一、一份 SSH 连接里有两层验证 <a class="header-anchor" href="#一、一份-ssh-连接里有两层验证" aria-label="Permalink to &quot;一、一份 SSH 连接里有两层验证&quot;">​</a></h2><p>敲下 <code>ssh root@192.168.10.129</code> 的时候，实际上发生了两次&quot;验证对方是谁&quot;的过程：</p><table tabindex="0"><thead><tr><th>验证对象</th><th>验证的是什么</th><th>证据放在哪里</th></tr></thead><tbody><tr><td>服务器身份</td><td>连接的这个 IP 是不是我以为的那台机器</td><td><code>~/.ssh/known_hosts</code></td></tr><tr><td>登录用户身份</td><td>我有没有权限登录这个系统账号</td><td>私钥文件、密码</td></tr></tbody></table><p>这两个容易搞混。打个比方：服务器身份验证像确认&quot;这栋楼是我要去的那栋楼&quot;，登录身份验证像确认&quot;我有这栋楼里某个房间的钥匙&quot;。楼对了但没钥匙，进不去；有钥匙但找错了楼，更危险。</p><p>看一个最基本的连接命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>只执行一条命令，不进入交互式 Shell：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;hostname -I&#39;</span></span></code></pre></div><p>脚本里用这种写法做批量检查时，判断退出码要留意：命令执行失败、SSH 认证失败、网络超时，都会返回非 0。如果要在脚本里区分&quot;连接不通&quot;和&quot;远端命令执行失败&quot;，要把连接检测和命令执行拆成两步：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ConnectTimeout=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;systemctl is-active --quiet nginx&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;nginx active&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 这里不区分是 SSH 不通还是 nginx inactive</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ssh failed or nginx inactive&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&amp;2</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p><code>ConnectTimeout=5</code> 是 TCP 连接超时，不是命令执行超时。网络不通时如果不设这个值，默认会等很久（通常几十秒到几分钟，取决于系统的 TCP 重传配置）。</p><h2 id="二、第一次连接-known-hosts-在干什么" tabindex="-1">二、第一次连接：known_hosts 在干什么 <a class="header-anchor" href="#二、第一次连接-known-hosts-在干什么" aria-label="Permalink to &quot;二、第一次连接：known_hosts 在干什么&quot;">​</a></h2><p>第一次连一台新机器时，客户端会打印：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The authenticity of host &#39;192.168.10.129 (192.168.10.129)&#39; can&#39;t be established.</span></span>
<span class="line"><span>ED25519 key fingerprint is SHA256:xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx.</span></span>
<span class="line"><span>Are you sure you want to continue connecting (yes/no/[fingerprint])?</span></span></code></pre></div><p>这是 SSH 客户端告诉你：我这辈子没见过这台机器，这是它报上来的公钥指纹，你帮我看一下对不对。</p><p>输入 <code>yes</code> 后，这个指纹存入 <code>~/.ssh/known_hosts</code>。以后每次连接，SSH 会拿 <code>known_hosts</code> 里存的公钥跟服务器当前报上来的公钥对比——一致就继续，不一致就报警：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@</span></span>
<span class="line"><span>@    WARNING: REMOTE HOST IDENTIFICATION HAS CHANGED!     @</span></span>
<span class="line"><span>@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@</span></span>
<span class="line"><span>IT IS POSSIBLE THAT SOMEONE IS DOING SOMETHING NASTY!</span></span></code></pre></div><p>翻译过来就是：之前你连的那台机器，现在换了一个身份，要么是机器重装了，要么是真的有人在中间冒充。</p><p>这个机制就是防止中间人攻击的。假设有人在网络中间架了一台机器，拦截你的 SSH 连接、假装是目标服务器，如果没有主机指纹校验，你敲的密码和命令都会落进中间人的手里。<code>known_hosts</code> 用&quot;第一次看到的指纹作基准&quot;来检测这种冒充。</p><p>当然，生产环境里主机密钥变化更多是因为重装系统、云主机重建、IP 复用。确认变化是合法的之后，删掉旧记录即可：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span></span></code></pre></div><p>提前把服务器指纹写进 <code>known_hosts</code>，可以避免第一次连接时的交互确认：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keyscan</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/known_hosts</span></span></code></pre></div><p>但这只是拿到对方报出来的公钥——指纹是不是真的，<code>ssh-keyscan</code> 不负责判断。严谨的做法是从装机流程、控制台元数据或 CMDB 拿到指纹后再写入。自动化脚本里直接用 <code>ssh-keyscan</code> 做信任写入，实际上绕过了主机验证。</p><p><code>StrictHostKeyChecking=no</code> 让 SSH 跳过主机指纹验证，连上去再说。这在临时测试环境里省事，但在脚本里长期用会让主机指纹校验形同虚设。真要让自动化脚本安全运行，正确做法是把指纹管理清楚，而不是关掉检查。</p><h2 id="三、密钥登录是怎么工作的" tabindex="-1">三、密钥登录是怎么工作的 <a class="header-anchor" href="#三、密钥登录是怎么工作的" aria-label="Permalink to &quot;三、密钥登录是怎么工作的&quot;">​</a></h2><p>密码登录的问题是：长度有限、可能被暴力尝试、多台机器上要记不同密码。密钥用数学关系替代记密码——私钥自己拿着，公钥放到服务器上。</p><p>连接时，服务端用公钥加密一个随机挑战值发给客户端，客户端用私钥解密并返回正确的应答。整个过程中私钥不离开本地，挑战值每次不同，所以即使通信被截获也无法重放。</p><p>生成一对 Ed25519 密钥：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 700</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ops@workstation-01&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span></span></code></pre></div><p>各参数的作用：</p><table tabindex="0"><thead><tr><th>参数</th><th>做什么</th></tr></thead><tbody><tr><td><code>-t ed25519</code></td><td>使用 Ed25519 算法。比 RSA 短、安全性高、签名快，现在主流 Linux 发行版都支持</td></tr><tr><td><code>-a 100</code></td><td>私钥口令的 KDF 轮次，增大暴力破解口令的代价。只对设置了 passphrase 的私钥有意义</td></tr><tr><td><code>-C</code></td><td>加在公钥末尾的注释，跟多把密钥时知道哪把属于谁</td></tr><tr><td><code>-f</code></td><td>指定输出文件，避免覆盖默认的 <code>id_ed25519</code></td></tr></tbody></table><p>生成后的文件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-rw------- 1 ops ops 411 May 21 10:00 /home/ops/.ssh/id_ed25519_ops</span></span>
<span class="line"><span>-rw-r--r-- 1 ops ops 100 May 21 10:00 /home/ops/.ssh/id_ed25519_ops.pub</span></span></code></pre></div><p>私钥是 <code>600</code>（仅自己可读写），公钥是 <code>644</code>（别人可读不可写但没问题，公钥本来就可以公开）。</p><p>把公钥放到目标服务器上：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-copy-id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops.pub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p><code>ssh-copy-id</code> 做的就是一件事：把本地公钥追加到远程的 <code>~/.ssh/authorized_keys</code> 文件末尾。如果目标机器没有这个命令，手动操作也一样：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops.pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    umask 077</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mkdir -p ~/.ssh</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    cat &gt;&gt; ~/.ssh/authorized_keys</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre></div><p><code>umask 077</code> 保证新建的 <code>.ssh</code> 目录和 <code>authorized_keys</code> 文件只有当前用户可以读写——服务端对权限很严格，目录或文件的权限太宽的话，sshd 会直接拒绝使用它们。</p><p>用指定私钥连接：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>如果私钥设置了 passphrase，每次输口令比较麻烦。<code>ssh-agent</code> 可以缓存解锁后的私钥，在当前会话里后续连接不需要再输：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 启动 agent，加载环境变量</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 输入一次口令，agent 记住解锁后的私钥</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # 看 agent 里加载了哪些 key</span></span></code></pre></div><h3 id="sshd-对权限的要求有多严" tabindex="-1">sshd 对权限的要求有多严 <a class="header-anchor" href="#sshd-对权限的要求有多严" aria-label="Permalink to &quot;sshd 对权限的要求有多严&quot;">​</a></h3><p>曾经碰到一个情况：公钥是对的，私钥也是对的，密码也确认没问题，但就是通不过密钥认证。最后在 <code>/var/log/secure</code> 里看到一行 <code>Authentication refused: bad ownership or modes for directory</code>——<code>~/.ssh</code> 的权限设成了 775，sshd 看到同组可写就直接拒绝了。</p><p>sshd 对文件权限的要求：</p><table tabindex="0"><thead><tr><th>路径</th><th>权限</th><th>为什么</th></tr></thead><tbody><tr><td><code>~/.ssh</code></td><td>700</td><td>不能让其他人或同组进入这个目录</td></tr><tr><td><code>~/.ssh/authorized_keys</code></td><td>600</td><td>不能让别人往里面加公钥</td></tr><tr><td>私钥文件</td><td>600</td><td>私钥泄露等于身份泄露</td></tr><tr><td>家目录</td><td>不能对组或其他人可写</td><td>否则别人可以改你的 <code>.ssh</code> 目录</td></tr></tbody></table><p>背后的道理很简单：如果目录对同组可写，组内其他人就可以重命名你的 <code>.ssh</code> 目录，然后建一个新的、放上自己的公钥。sshd 拒绝这种配置是为了防止权限漏洞被利用。</p><h2 id="四、-ssh-config" tabindex="-1">四、~/.ssh/config <a class="header-anchor" href="#四、-ssh-config" aria-label="Permalink to &quot;四、~/.ssh/config&quot;">​</a></h2><p>机器一多，每次都敲完整的 <code>ssh -p 2222 -i ~/.ssh/prod_key user@10.x.x.x</code> 又长又容易打错。<code>~/.ssh/config</code> 把这些参数固化下来，之后直接 <code>ssh 别名</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host test-rocky</span></span>
<span class="line"><span>    HostName 192.168.10.129</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    Port 22</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_ops</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span>
<span class="line"><span>    ServerAliveInterval 30</span></span>
<span class="line"><span>    ServerAliveCountMax 3</span></span></code></pre></div><p>配置项的作用：</p><table tabindex="0"><thead><tr><th>字段</th><th>作用</th></tr></thead><tbody><tr><td><code>Host</code></td><td>本地用的别名，支持通配符（<code>*</code> 匹配任意）</td></tr><tr><td><code>HostName</code></td><td>真实地址，IP 或域名</td></tr><tr><td><code>User</code></td><td>登录用户名</td></tr><tr><td><code>Port</code></td><td>SSH 端口</td></tr><tr><td><code>IdentityFile</code></td><td>使用哪把私钥</td></tr><tr><td><code>IdentitiesOnly yes</code></td><td>只尝试配置里指定的私钥，不试 ssh-agent 里其他的</td></tr><tr><td><code>ServerAliveInterval</code></td><td>客户端每隔 N 秒发一次心跳，防止空闲连接被中间设备断开</td></tr><tr><td><code>ServerAliveCountMax</code></td><td>连续几次收不到心跳响应就断开</td></tr></tbody></table><p><code>IdentitiesOnly yes</code> 值得单独说一下。ssh-agent 里加载的私钥多的时候，客户端可能逐把试过去，试到某一把触发服务端的 <code>Too many authentication failures</code> 就断了。指定 <code>IdentitiesOnly yes</code> 后只试配置里写的那一把，排查认证问题会清晰很多。</p><p>按环境拆配置，用通配符匹配：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host prod-*</span></span>
<span class="line"><span>    User ops</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_prod</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Host test-*</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_test</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span></code></pre></div><p>这样 <code>prod-web-01</code> 和 <code>prod-db-02</code> 都会走生产环境的 key，<code>test-*</code> 走测试环境的 key。按环境隔离私钥的习惯，至少能让测试 key 的泄露不影响生产。</p><p>配置文件的权限也建议收紧：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/config</span></span></code></pre></div><p>毕竟里面写了用户名、跳板机地址、私钥路径这些信息。</p><p>想看某个别名最终展开后的所有配置项——包括配置文件、默认值和命令行参数合并后的结果：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -G</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-rocky</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> less</span></span></code></pre></div><p>这条命令排查配置问题时很实用。比如你以为用了某把 key，实际生效的是另一把，<code>-G</code> 能直接看到 <code>identityfile</code> 字段的最终值。</p><h2 id="五、proxyjump-通过跳板机连接内网" tabindex="-1">五、ProxyJump：通过跳板机连接内网 <a class="header-anchor" href="#五、proxyjump-通过跳板机连接内网" aria-label="Permalink to &quot;五、ProxyJump：通过跳板机连接内网&quot;">​</a></h2><p>生产服务器经常没有公网 IP，暴露在公网的只有一台跳板机（堡垒机）。连接流程是：先 SSH 到跳板机，再从跳板机 SSH 到目标机器。</p><p>OpenSSH 7.3 之后用 <code>ProxyJump</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -J</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@203.0.113.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@10.10.1.21</span></span></code></pre></div><p>写进 <code>~/.ssh/config</code> 更直观：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host jump</span></span>
<span class="line"><span>    HostName 203.0.113.10</span></span>
<span class="line"><span>    User ops</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_jump</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Host app-01</span></span>
<span class="line"><span>    HostName 10.10.1.21</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_inner</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span>
<span class="line"><span>    ProxyJump jump</span></span></code></pre></div><p>之后直接 <code>ssh app-01</code>，SSH 会自动先连跳板机再转发到目标。</p><p>多条跳板的情况用逗号分隔：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -J</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@jump1,user@jump2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target</span></span></code></pre></div><p>链路是：<code>本地 -&gt; jump1 -&gt; jump2 -&gt; target</code>。</p><p>老版本的 OpenSSH 可能没有 <code>ProxyJump</code>，只能用 <code>ProxyCommand</code> 实现相同效果：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host app-01-old</span></span>
<span class="line"><span>    HostName 10.10.1.21</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    ProxyCommand ssh jump -W %h:%p</span></span></code></pre></div><p><code>-W %h:%p</code> 表示&quot;把标准输入输出转发到这个主机和端口&quot;，%h 和 %p 会被替换成 <code>HostName</code> 和 <code>Port</code> 的值。<code>ProxyJump</code> 本质上就是 <code>ProxyCommand ssh -W</code> 的简化写法。</p><p>注意 ProxyJump 只是解决了&quot;怎么连过去&quot;的链路问题。堡垒机还要管&quot;谁能连、用什么身份、做什么操作&quot;这些事，那是另一个层面的事了。</p><h2 id="六、ssh-端口转发" tabindex="-1">六、SSH 端口转发 <a class="header-anchor" href="#六、ssh-端口转发" aria-label="Permalink to &quot;六、SSH 端口转发&quot;">​</a></h2><p>端口转发把本地和远程的 TCP 端口通过 SSH 隧道连起来。常见的用场：访问只有内网 IP 的数据库、临时看内网的管理后台、或者让外网同事临时看本机开发环境的服务。</p><h3 id="本地转发-l-本机访问远端内网资源" tabindex="-1">本地转发（-L）：本机访问远端内网资源 <a class="header-anchor" href="#本地转发-l-本机访问远端内网资源" aria-label="Permalink to &quot;本地转发（-L）：本机访问远端内网资源&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:127.0.0.1:5432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ExitOnForwardFailure=yes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ops@db-gateway</span></span></code></pre></div><p>这条命令的效果是：本机的 <code>15432</code> 端口被映射到了 <code>db-gateway</code> 这台机器能访问到的 <code>127.0.0.1:5432</code>。本机访问 <code>localhost:15432</code>，就等于访问 <code>db-gateway</code> 本机的 PostgreSQL。</p><p>如果数据库不在 <code>db-gateway</code> 上，而是在它能连通的内网另一台机器上：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:10.10.2.15:5432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ops@db-gateway</span></span></code></pre></div><p>这里的一个关键点是：<code>10.10.2.15</code> 是从 <code>db-gateway</code> 这台机器的视角来解析的，不是从本机。一开始用的时候容易把方向搞反，以为填的是本机能看到的地址，实际上应该填跳板机能看到的地址。<code>-L</code> 的参数格式就是 <code>本地端口:远端目标:远端端口</code>，这里的&quot;远端目标&quot;是中间机视角下的地址。</p><p>参数拆解：</p><table tabindex="0"><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td><code>-N</code></td><td>不执行远程命令，只建隧道</td></tr><tr><td><code>-L 15432:10.10.2.15:5432</code></td><td>本机 15432 -&gt; 走 db-gateway 隧道 -&gt; 10.10.2.15 的 5432</td></tr><tr><td><code>-o ExitOnForwardFailure=yes</code></td><td>端口绑定失败时直接退出，而不是静默继续运行</td></tr></tbody></table><p><code>ExitOnForwardFailure=yes</code> 在脚本里很重要。如果不设置，端口绑定失败（比如被其他进程占用了）但 SSH 连接本身成功了，转发进程会在后台静默运行，后面排查时会发现端口通了但不是预期的服务。</p><h3 id="远程转发-r-让远端访问本机服务" tabindex="-1">远程转发（-R）：让远端访问本机服务 <a class="header-anchor" href="#远程转发-r-让远端访问本机服务" aria-label="Permalink to &quot;远程转发（-R）：让远端访问本机服务&quot;">​</a></h3><p>方向反一下——把本机或本机能访问到的服务暴露到远端：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18080:127.0.0.1:8080</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ops@public-gateway</span></span></code></pre></div><p>执行后，在 <code>public-gateway</code> 上访问 <code>127.0.0.1:18080</code>，流量回到本机的 <code>8080</code>。</p><p>一个具体场景：内网开发机上跑了一个 Web 服务，临时给外网同事看。用远程转发把一台有公网 IP 的 VPS 上的端口映射到本地开发的端口，同事访问 VPS 的地址就能看到开发机上的服务。</p><p>远程转发有个默认限制：目标机器上的监听只绑在 <code>127.0.0.1</code>，也就是说只有目标机器自己可以访问这个被映射的端口。如果希望目标机器所在的网络里其他机器也能访问这个映射端口，要在 sshd 配置里打开 <code>GatewayPorts yes</code>（或者 <code>GatewayPorts clientspecified</code>）。</p><h3 id="动态转发-d-socks-代理" tabindex="-1">动态转发（-D）：SOCKS 代理 <a class="header-anchor" href="#动态转发-d-socks-代理" aria-label="Permalink to &quot;动态转发（-D）：SOCKS 代理&quot;">​</a></h3><p>在本地起一个 SOCKS 代理端口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 127.0.0.1:1080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@gateway</span></span></code></pre></div><p>配置浏览器或应用使用 SOCKS5 代理 <code>127.0.0.1:1080</code> 后，这些应用的网络请求都会通过 <code>gateway</code> 那台机器转发出去。等于把 <code>gateway</code> 当成上网出口。</p><p>测试代理是否生效：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --socks5-hostname</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 127.0.0.1:1080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com</span></span></code></pre></div><p><code>--socks5-hostname</code> 和 <code>--socks5</code> 的区别在于域名解析发生在哪一端。<code>--socks5</code> 是本机解析域名、代理只负责转发 IP 包；<code>--socks5-hostname</code> 是域名解析也交给代理端处理。内网里有些域名在公网 DNS 解析不了，要用 <code>--socks5-hostname</code> 把解析也送到远端。</p><h3 id="隧道放后台" tabindex="-1">隧道放后台 <a class="header-anchor" href="#隧道放后台" aria-label="Permalink to &quot;隧道放后台&quot;">​</a></h3><p>加 <code>-f</code> 让 SSH 认证成功后进入后台：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:127.0.0.1:5432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ExitOnForwardFailure=yes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ops@db-gateway</span></span></code></pre></div><p><code>-f</code> 必须在命令行上有 <code>-N</code> 或者指定了远程命令时才能用，因为它要先完成认证，然后把自己放到后台。</p><h2 id="七、连接复用-controlmaster" tabindex="-1">七、连接复用：ControlMaster <a class="header-anchor" href="#七、连接复用-controlmaster" aria-label="Permalink to &quot;七、连接复用：ControlMaster&quot;">​</a></h2><p>短时间内多次连接同一台机器时，每次都要重新走 TCP 握手和密钥认证。<code>ControlMaster</code> 用第一条连接的通道来承载后续连接，省掉握手开销：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host *</span></span>
<span class="line"><span>    ControlMaster auto</span></span>
<span class="line"><span>    ControlPath ~/.ssh/controlmasters/%r@%h:%p</span></span>
<span class="line"><span>    ControlPersist 10m</span></span></code></pre></div><p>先建目录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/controlmasters</span></span></code></pre></div><p>配置说明：</p><table tabindex="0"><thead><tr><th>配置</th><th>作用</th></tr></thead><tbody><tr><td><code>ControlMaster auto</code></td><td>自动尝试复用已有连接，没有就新建</td></tr><tr><td><code>ControlPath</code></td><td>控制 socket 的存放路径。<code>%r</code>=用户名，<code>%h</code>=目标主机，<code>%p</code>=端口</td></tr><tr><td><code>ControlPersist 10m</code></td><td>主连接在最后一个会话结束后继续保持 10 分钟</td></tr></tbody></table><p>管理已有的复用连接：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 看复用连接的状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 主动关掉主连接（连同所有复用的会话）</span></span></code></pre></div><h2 id="八、连接排错" tabindex="-1">八、连接排错 <a class="header-anchor" href="#八、连接排错" aria-label="Permalink to &quot;八、连接排错&quot;">​</a></h2><p>围绕连接失败的问题，可以按从外到内的顺序查。</p><h3 id="客户端侧-看清到底发生了什么" tabindex="-1">客户端侧：看清到底发生了什么 <a class="header-anchor" href="#客户端侧-看清到底发生了什么" aria-label="Permalink to &quot;客户端侧：看清到底发生了什么&quot;">​</a></h3><p><code>-v</code> 输出握手、认证每一步的日志：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vvv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>日志里重点关注这几类信息：</p><table tabindex="0"><thead><tr><th>日志关键字</th><th>大概含义</th></tr></thead><tbody><tr><td><code>Offering public key</code></td><td>客户端正在尝试某把公钥</td></tr><tr><td><code>Authentications that can continue</code></td><td>服务端允许哪些认证方式</td></tr><tr><td><code>Permission denied</code></td><td>认证失败，可能是用户、key、权限</td></tr><tr><td><code>Connection timed out</code></td><td>网络不通，查路由、防火墙、安全组</td></tr><tr><td><code>Connection refused</code></td><td>网络可达但端口没有监听或被主动拒</td></tr></tbody></table><p>排查&quot;到底是 key 的问题还是密码兜底成功了&quot;时，可以强制只走公钥认证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PreferredAuthentications=publickey</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PasswordAuthentication=no</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    root@192.168.10.129</span></span></code></pre></div><p>这样就能确认：刚才登录成功是因为 key 生效了，还是因为密码兜底成功了（而 key 其实没配好）。</p><h3 id="网络侧-端口是否可达" tabindex="-1">网络侧：端口是否可达 <a class="header-anchor" href="#网络侧-端口是否可达" aria-label="Permalink to &quot;网络侧：端口是否可达&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span></span></code></pre></div><p>如果没有 <code>nc</code>，Bash 内置的 <code>/dev/tcp</code> 也能临时测：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;/dev/tcp/192.168.10.129/22&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$?</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 0 表示 TCP 建连成功，非 0 表示失败或超时</span></span></code></pre></div><h3 id="服务端侧-sshd-日志" tabindex="-1">服务端侧：sshd 日志 <a class="header-anchor" href="#服务端侧-sshd-日志" aria-label="Permalink to &quot;服务端侧：sshd 日志&quot;">​</a></h3><p>服务端日志通常能直接看到失败原因，比在客户端反复试更直截了当。</p><p>RHEL/Rocky 系：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/secure</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span></span></code></pre></div><p>Debian/Ubuntu 系：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/auth.log</span></span></code></pre></div><p>systemd 环境：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span></span></code></pre></div><h3 id="服务端权限检查" tabindex="-1">服务端权限检查 <a class="header-anchor" href="#服务端权限检查" aria-label="Permalink to &quot;服务端权限检查&quot;">​</a></h3><p>如果日志里出现了 <code>bad ownership or modes</code>，检查这几项：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ld</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 家目录不能对组或其他人可写</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ld</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 应该是 700</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/authorized_keys</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 应该是 600</span></span></code></pre></div><p>SELinux 环境里权限对了但上下文不对也会失败：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">restorecon</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Rv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span></span></code></pre></div><h3 id="修改-sshd-配置时的安全习惯" tabindex="-1">修改 sshd 配置时的安全习惯 <a class="header-anchor" href="#修改-sshd-配置时的安全习惯" aria-label="Permalink to &quot;修改 sshd 配置时的安全习惯&quot;">​</a></h3><p>改完 <code>/etc/ssh/sshd_config</code> 后需要让服务重新加载配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span></span></code></pre></div><p><code>reload</code> 不会断开已有的连接，但修改想生效的新连接会走新配置。操作时的习惯是：保留一个已登录的窗口不要关，另开一个终端测新配置能否登录，确认没问题再关旧窗口。这样即使配置有误导致后续连接被拒，已有的会话还在，可以回滚。</p>`,149)])])}const g=a(n,[["render",p]]);export{r as __pageData,g as default};
